export interface Preference {
    appName: string;
    userName: string;
    preferenceName: string;
    value: any;
    context: string;
}
export interface ScanPreferenceResponse {
    preferences: Preference[];
    nextToken: string;
}
export interface HarmonyPreferences {
    /**
     * Retrieves the current logon user's preference for the given {@code appName}. The preference to
     * retrieve is identified by the specified {@code preferenceName} and {@code context}.
     *
     * @param {Object} params
     * @param {String} [params.appName=window.harmony.api.getAppName()]
     *                    The Harmony application name for which the preference to get is associated with.
     * @param {String} params.preferenceName The name of the preference to get.
     * @param {String} [params.context] The associated context of the preference to get.
     * @param {Boolean} refresh True to refresh from the server.
     *
     * @return a Promise that resolves to {@code Preference} object.
     */
    getPreferences: ({ appName, preferenceName, context }: {
        appName?: string;
        preferenceName: string;
        context?: string;
    }, refresh?: boolean) => Promise<Preference>;
    /**
     * Lists the specified user's preferences for the given {@code appName} and {@code preferenceName}.
     * The result will be paginated and you need to pass the {@code nextToken} value from the response of previous page request,
     * as {@code startToken} of the next page request. When the {@code nextToken} value is null from a response,
     * it means there is no more next page.
     *
     * @param {Object} params
     * @param {String} [params.appName=window.harmony.api.getAppName()]
     *                    The Harmony application name for which the preference to scan is associated with.
     * @param {String} [params.userName=window.harmony.api.getUserName()]
     *                    The name of the user whose preferences will get fetched.
     * @param {String} [params.preferenceName]
     *                    The name of the user preference to fetch. If not specified, all the specified
     *                    user's preferences for the {@code appName} will be fetched.
     * @param {Number} [params.pageSize=20] The maximum number of preferences to return for the current scan request.
     * @param {String} [params.startToken] The start token to use for scanning preferences.
     *
     * @return a Promise that resolves to a {@code ScanPreferenceResponse} object with the list of {@code Preference} object
     *              and optional {@code startToken}.
     */
    scanPreferences: ({ appName, userName, preferenceName, pageSize, startToken }?: {
        appName?: string;
        userName?: string;
        preferenceName?: string;
        pageSize?: number;
        startToken?: string;
    }) => Promise<ScanPreferenceResponse>;
    /**
     * Updates the current logon user's preference for the given {@code appName}. The preference to
     * update is identified by the specified {@code preferenceName}. When {@code value} is not specified,
     * or is null/empty, the identified {@code preferenceName} for the given {@code appName} is removed.
     *
     * @param {Object} params
     * @param {String} [params.appName=window.harmony.api.getAppName()]
     *                    The Harmony application name for which the specified {@code preferenceName}
     *                    is associated with.
     * @param {String} params.preferenceName
     *                    The name of the preference. It should be a valid preference name that is
     *                    associated with the application name.
     * @param {*} [params.value]
     *                    The value to set for the specified {@code preferenceName}. When not specified,
     *                    or set to null, the preference entry for the specified preference name
     *                    is removed.
     * @param {String} [params.context]
     *                    The context to set for the current preference.
     *
     * @return a Promise that resolves to an object with `updated` boolean property.
     */
    writePreferences: ({ appName, preferenceName, value, context }: {
        appName: string;
        preferenceName: string;
        value?: any;
        context?: string;
    }) => Promise<{
        updated: boolean;
    }>;
}
